class Solution(object):
    def minReverseOperations(self, n, p, banned, k):
        """
        :type n: int
        :type p: int
        :type banned: List[int]
        :type k: int
        :rtype: List[int]
        """
        # pre-process
        from sortedcontainers import SortedList
        evens = SortedList(range(0, n, 2))
        odds = SortedList(range(1, n, 2))
        evens.add(n)
        odds.add(n)
        for b in banned:
            if b % 2 == 0:
                evens.discard(b)
            else:
                odds.discard(b)
        # print(evens)
        # print(odds)

        # helper function
        def getVisited(target):
            return evens if target % 2 == 0 else odds

        # process
        from collections import deque
        bfs = deque()
        bfs.append(p)
        visited = getVisited(p)
        visited.discard(p)

        ans = [-1] * n
        step = 0
        while bfs:
            size = len(bfs)
            for _ in range(size):
                # update ans
                curr = bfs.popleft()
                ans[curr] = step

                # judge parity and get visited
                bound = curr - (k - 1)
                visited = getVisited(bound)

                # get left and right
                left = max(0 , curr - (k - 1))
                right = min(n - 1, curr + (k - 1))

                # get the leftest valid next point
                left_target = left + k - 1
                left_nxt = left + (left_target - curr)

                # get the rightest valid next point
                right_target = right
                right_nxt = right - (k - 1) + (right_target - curr)

                # search and update
                idx = visited.bisect_left(left_nxt)
                while visited[idx] <= right_nxt:
                    bfs.append(visited[idx])
                    visited.discard(visited[idx])

            step += 1
        return ans


